import{ab as e,G as i,H as t,ad as o}from"./framework-756f1659.js";const l={},n=o('<h3 id="docker-ps-options" tabindex="-1"><a class="header-anchor" href="#docker-ps-options" aria-hidden="true">#</a> docker ps [OPTIONS]</h3><p><strong>列出容器</strong></p><p>OPTIONS说明：</p><p>-a :显示所有的容器，包括未运行的。</p><p>-q :静默模式，只显示容器编号。</p><p>--format :指定返回值的模板文件。</p><p>-l :显示最近创建的容器。</p><p>-n :列出最近创建的n个容器。</p><p>--no-trunc :不截断输出。</p><p>-s :显示总的文件大小。</p><p>-f 或-filter :根据条件过滤显示的内容。格式为key=value，如果超过一个过滤，就传递多个标志（如-filter &quot;foo=bar&quot; -filter &quot;bif=baz&quot;）</p><div class="hint-container info"><p class="hint-container-title">-f 目前支持的过滤器</p><ul><li>id (容器的id）</li><li>label</li><li>name（容器名称）</li><li>exited （整数-容器退出状态码，只有在使用-all才有用）</li><li>status 容器状态（created,restarting,running,paused,exited,dead）</li><li>ances tor 过滤从指定镜像创建的容器</li><li>before （容器的名称或id）,过滤在给定id或名称之后创建的容器</li><li>isolation (default process hyperv) (windows daemon only)</li><li>volume (数据卷名称或挂载点)，--过滤挂载有指定数据卷的容器</li><li>network（网络id或名称），过滤连接到指定网络的容器</li></ul><p>如：<code>docker ps -f status=exited // 列出已退出的容器</code></p></div>',12),a=[n];function r(s,d){return i(),t("div",null,a)}const c=e(l,[["render",r],["__file","index.html.vue"]]);export{c as default};
